import { alpha } from '@mui/material/styles';

export const getCommonStyles = (theme) => ({
  card: {
    height: '100%',
    transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(145deg, rgba(41, 49, 79, 0.8), rgba(41, 49, 79, 0.9))'
      : 'linear-gradient(145deg, rgba(255,255,255,0.95), rgba(255,255,255,0.98))',
    backdropFilter: 'blur(10px)',
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.1)'
      : '1px solid rgba(255,255,255,0.7)',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 20px 0 rgba(0,0,0,0.25), 0 3px 8px -2px rgba(0,0,0,0.35)'
      : '0 4px 20px 0 rgba(31,38,135,0.18), 0 3px 8px -2px rgba(31,38,135,0.25)',
    '&:hover': {
      transform: 'translateY(-4px)',
      boxShadow: theme.palette.mode === 'dark'
        ? '0 8px 24px 0 rgba(0,0,0,0.35), 0 4px 10px -2px rgba(0,0,0,0.45)'
        : '0 8px 24px 0 rgba(31,38,135,0.28), 0 4px 10px -2px rgba(31,38,135,0.35)',
    }
  },

  headerCard: {
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(90deg, rgba(41, 49, 79, 0.95), rgba(41, 49, 79, 0.95))'
      : 'linear-gradient(90deg, #3949ab 0%, #5e35b1 100%)',
    color: '#fff',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 20px 0 rgba(0,0,0,0.25), 0 3px 8px -2px rgba(0,0,0,0.35)'
      : '0 4px 20px 0 rgba(31,38,135,0.18), 0 3px 8px -2px rgba(31,38,135,0.25)',
    mb: 1.5,
    backdropFilter: 'blur(10px)',
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.1)'
      : '1px solid rgba(255,255,255,0.15)',
  },

  actionButton: {
    borderRadius: 2,
    px: 3,
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(45deg, rgba(41, 49, 79, 0.95) 30%, rgba(41, 49, 79, 0.95) 90%)'
      : 'linear-gradient(45deg, #3949ab 30%, #5e35b1 90%)',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 3px 12px 0 rgba(0,0,0,0.25)'
      : '0 3px 12px 0 rgba(31,38,135,0.25)',
    '&:hover': {
      background: theme.palette.mode === 'dark' 
        ? 'linear-gradient(45deg, rgba(41, 49, 79, 1) 20%, rgba(41, 49, 79, 1) 100%)'
        : 'linear-gradient(45deg, #3949ab 20%, #5e35b1 100%)',
      boxShadow: theme.palette.mode === 'dark'
        ? '0 4px 16px 0 rgba(0,0,0,0.35)'
        : '0 4px 16px 0 rgba(31,38,135,0.35)',
    },
  },

  dialog: {
    borderRadius: 2,
    background: theme.palette.mode === 'dark'
      ? 'linear-gradient(145deg, rgba(41, 49, 79, 0.95), rgba(41, 49, 79, 0.95))'
      : '#fff',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 8px 32px 0 rgba(0,0,0,0.35)'
      : '0 8px 32px 0 rgba(31,38,135,0.25)',
  },

  tableContainer: {
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 20px 0 rgba(0,0,0,0.25), 0 3px 8px -2px rgba(0,0,0,0.35)'
      : '0 4px 20px 0 rgba(31,38,135,0.18), 0 3px 8px -2px rgba(31,38,135,0.25)',
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(145deg, rgba(41, 49, 79, 0.8), rgba(41, 49, 79, 0.9))'
      : 'linear-gradient(145deg, rgba(255,255,255,0.95), rgba(255,255,255,0.98))',
    borderRadius: 1,
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.1)'
      : '1px solid rgba(255,255,255,0.7)',
    '& .MuiTableCell-root': {
      borderColor: theme.palette.mode === 'dark' 
        ? 'rgba(255, 255, 255, 0.1)'
        : 'rgba(0, 0, 0, 0.1)',
      color: theme.palette.mode === 'dark'
        ? 'rgba(255, 255, 255, 0.85)'
        : 'inherit',
    },
    '& .MuiTableHead-root .MuiTableCell-root': {
      fontWeight: 600,
      color: theme.palette.mode === 'dark'
        ? 'rgba(255, 255, 255, 0.95)'
        : 'rgba(0, 0, 0, 0.87)',
    }
  },

  chip: {
    primary: {
      borderRadius: 1,
      background: theme.palette.mode === 'dark' 
        ? alpha(theme.palette.primary.main, 0.2)
        : alpha(theme.palette.primary.main, 0.1),
      color: theme.palette.mode === 'dark'
        ? theme.palette.primary.light
        : theme.palette.primary.main,
    },
    success: {
      borderRadius: 1,
      background: theme.palette.mode === 'dark'
        ? alpha(theme.palette.success.main, 0.2)
        : alpha(theme.palette.success.main, 0.1),
      color: theme.palette.success.main,
    },
    error: {
      borderRadius: 1,
      background: theme.palette.mode === 'dark'
        ? alpha(theme.palette.error.main, 0.2)
        : alpha(theme.palette.error.main, 0.1),
      color: theme.palette.error.main,
    },
    warning: {
      borderRadius: 1,
      background: theme.palette.mode === 'dark'
        ? alpha(theme.palette.warning.main, 0.2)
        : alpha(theme.palette.warning.main, 0.1),
      color: theme.palette.warning.main,
    },
  },

  iconButton: {
    color: 'rgba(255,255,255,0.85)',
    '&:hover': { 
      color: '#fff',
      backgroundColor: 'rgba(255,255,255,0.15)' 
    }
  },

  textField: {
    '& .MuiOutlinedInput-root': {
      '&:hover fieldset': {
        borderColor: theme.palette.primary.main,
      },
    },
  },
});
